import React, { useState } from "react";

export default function SearchSection({ onSearch = async () => {} }) {
  const [q, setQ] = useState("");

  const submit = (e) => {
    e.preventDefault();
    const v = q.trim();
    if (v) onSearch(v);
  };

  return (
    <form
      onSubmit={submit}
      className="w-full mx-auto max-w-3xl flex items-center gap-2 rounded-2xl border border-white/20 bg-white/80 backdrop-blur px-3 py-2 shadow"
    >
      <input
        value={q}
        onChange={(e) => setQ(e.target.value)}
        placeholder="Search city or ZIP…"
        className="flex-1 bg-transparent outline-none text-sm md:text-base placeholder:opacity-60"
      />
      <button
        type="submit"
        className="rounded-xl px-4 py-2 text-sm font-medium text-white bg-purple-600"
      >
        Search
      </button>
    </form>
  );
}
